-- PostgreSQL Schema\n\nCREATE TABLE users (\n    user_id SERIAL PRIMARY KEY,\n    username VARCHAR(50) NOT NULL,\n    email VARCHAR(100) NOT NULL UNIQUE,\n    password_hash VARCHAR(255) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE cantine (\n    cantine_id SERIAL PRIMARY KEY,\n    name VARCHAR(100) NOT NULL,\n    location VARCHAR(255) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE sommelier (\n    sommelier_id SERIAL PRIMARY KEY,\n    user_id INT NOT NULL REFERENCES users(user_id),\n    experience_years INT NOT NULL,\n    specialization VARCHAR(100),\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE messages (\n    message_id SERIAL PRIMARY KEY,\n    sender_id INT NOT NULL REFERENCES users(user_id),\n    receiver_id INT NOT NULL REFERENCES users(user_id),\n    content TEXT NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE wines (\n    wine_id SERIAL PRIMARY KEY,\n    name VARCHAR(100) NOT NULL,\n    year INT NOT NULL,\n    cantine_id INT NOT NULL REFERENCES cantine(cantine_id),\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE events (\n    event_id SERIAL PRIMARY KEY,\n    cantine_id INT NOT NULL REFERENCES cantine(cantine_id),\n    event_date TIMESTAMP NOT NULL,\n    description TEXT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n